8→function getMonday(d) {
9→  const date = new Date(d);
10→  const day = date.getDay();
11→  const diff = date.getDate() - day + (day === 0 ? -6 : 1);
12→  date.setDate(diff);
13→  return date.toISOString().split('T')[0];
14→}
